public class FluentBuilder {
    static class Query {
        String table = "";
        String where = "";
        int limit = -1;
        Query from(String t) { table = t; return this; }
        Query where(String w) { where = w; return this; }
        Query limit(int n) { limit = n; return this; }
        String build() {
            String q = "SELECT * FROM " + table;
            if (!where.isEmpty()) q += " WHERE " + where;
            if (limit > 0) q += " LIMIT " + limit;
            return q;
        }
    }
    public static void main(String[] args) {
        String q = new Query().from("users").where("age>18").limit(10).build();
        System.out.println(q);
    }
}
